import { derived } from 'svelte/store';
import { encodeSudoku } from '@sudoku/sencode';
import { hints } from './hints';
import { gameStore } from './gameStore';

const initialGridStore = derived(gameStore, $gameStore => $gameStore.initialGrid);
const currentGridStore = derived(gameStore, $gameStore => $gameStore.grid);

export const grid = {
  subscribe: initialGridStore.subscribe,

  generate(difficulty) {
    gameStore.startNew(difficulty);
  },

  decodeSencode(sencode) {
    gameStore.startCustom(sencode);
  },

  get(gridStore, x, y) {
    return gridStore[y][x];
  },

  getSencode(gridStore) {
    return encodeSudoku(gridStore);
  },
};

export const userGrid = {
  subscribe: currentGridStore.subscribe,

  set(pos, value) {
    return gameStore.guess({
      row: pos.y,
      col: pos.x,
      value,
    });
  },

  applyHint(pos) {
    hints.useHint();
    return gameStore.applyHint({
      row: pos.y,
      col: pos.x,
    });
  },
};

export const invalidCells = derived(
  gameStore,
  $gameStore => $gameStore.invalidCells ?? [],
  [],
);
